const { BlobServiceClient, StorageSharedKeyCredential } = require('@azure/storage-blob');
const { DefaultAzureCredential } = require('@azure/identity');

// Method 1: Using Managed Identity (recommended for production)
const accountName = process.env.AZURE_STORAGE_ACCOUNT_NAME;
const credential = new DefaultAzureCredential();
const blobServiceClient = new BlobServiceClient(
  `https://${accountName}.blob.core.windows.net`,
  credential
);

// Disable public access at storage account level
async function disablePublicAccess() {
  try {
    // Set account-level public access policy
    await blobServiceClient.setProperties({
      blobPublicAccess: false, // Disallow public access entirely
      staticWebsite: {
        enabled: false
      },
      cors: [],
      defaultServiceVersion: '2021-08-06'
    });

    console.log('✓ Public blob access disabled at storage account level');

    // Verify the setting
    const properties = await blobServiceClient.getProperties();
    console.log('Public Access Allowed:', properties.allowBlobPublicAccess); // Should be false

  } catch (error) {
    console.error('Failed to disable public access:', error.message);
    throw error;
  }
}

// Ensure all containers are private
async function enforcePrivateContainers() {
  try {
    const containers = blobServiceClient.listContainers();

    for await (const container of containers) {
      const containerClient = blobServiceClient.getContainerClient(container.name);

      // Set container access to private (no anonymous access)
      await containerClient.setAccessPolicy('none', []);
      console.log(`✓ Container '${container.name}' set to private access`);
    }
  } catch (error) {
    console.error('Failed to enforce private containers:', error.message);
    throw error;
  }
}

// Execute security hardening
async function hardenStorageAccount() {
  console.log('Starting Azure Blob Storage security hardening...');
  await disablePublicAccess();
  await enforcePrivateContainers();
  console.log('✓ Storage account hardening complete');
}

hardenStorageAccount().catch(console.error);

# terraform/storage-account-private-endpoint.tf

# Create storage account with network restrictions
resource "azurerm_storage_account" "secure" {
  name                     = "secureblob${random_string.suffix.result}"
  resource_group_name      = azurerm_resource_group.main.name
  location                 = azurerm_resource_group.main.location
  account_tier             = "Standard"
  account_replication_type = "GRS"
  account_kind             = "StorageV2"

  # Disable public access completely
  public_network_access_enabled   = false
  allow_nested_items_to_be_public = false
  shared_access_key_enabled       = false  # Force Azure AD authentication

  # Enable encryption and advanced threat protection
  enable_https_traffic_only = true
  min_tls_version          = "TLS1_2"

  infrastructure_encryption_enabled = true

  blob_properties {
    versioning_enabled       = true
    change_feed_enabled      = true
    last_access_time_enabled = true

    delete_retention_policy {
      days = 30
    }

    container_delete_retention_policy {
      days = 30
    }
  }

  network_rules {
    default_action             = "Deny"
    bypass                     = ["AzureServices", "Logging", "Metrics"]
    ip_rules                   = []  # No public IP allowlist
    virtual_network_subnet_ids = []  # Managed via Private Endpoint only
  }

  tags = {
    Environment = "Production"
    Security    = "HighlyRestricted"
  }
}

# Create private DNS zone for blob storage
resource "azurerm_private_dns_zone" "blob" {
  name                = "privatelink.blob.core.windows.net"
  resource_group_name = azurerm_resource_group.main.name
}

# Link DNS zone to VNet
resource "azurerm_private_dns_zone_virtual_network_link" "blob" {
  name                  = "blob-dns-link"
  resource_group_name   = azurerm_resource_group.main.name
  private_dns_zone_name = azurerm_private_dns_zone.blob.name
  virtual_network_id    = azurerm_virtual_network.main.id
  registration_enabled  = false
}

# Create private endpoint
resource "azurerm_private_endpoint" "blob" {
  name                = "${azurerm_storage_account.secure.name}-pe"
  location            = azurerm_resource_group.main.location
  resource_group_name = azurerm_resource_group.main.name
  subnet_id           = azurerm_subnet.private_endpoints.id

  private_service_connection {
    name                           = "${azurerm_storage_account.secure.name}-psc"
    private_connection_resource_id = azurerm_storage_account.secure.id
    subresource_names              = ["blob"]
    is_manual_connection           = false
  }

  private_dns_zone_group {
    name                 = "blob-dns-zone-group"
    private_dns_zone_ids = [azurerm_private_dns_zone.blob.id]
  }

  tags = {
    Environment = "Production"
  }
}

# Output private endpoint IP
output "private_endpoint_ip" {
  value = azurerm_private_endpoint.blob.private_service_connection[0].private_ip_address
  description = "Private IP address for blob storage (accessible only within VNet)"
}

