const {
  BlobServiceClient,
  StorageSharedKeyCredential,
  BlobSASPermissions,
  generateBlobSASQueryParameters
} = require('@azure/storage-blob');

// Initialize with account key (store in Azure Key Vault in production)
const accountName = process.env.AZURE_STORAGE_ACCOUNT_NAME;
const accountKey = process.env.AZURE_STORAGE_ACCOUNT_KEY; // Retrieved from Key Vault
const containerName = 'secure-uploads';

const credential = new StorageSharedKeyCredential(accountName, accountKey);
const blobServiceClient = new BlobServiceClient(
  `https://${accountName}.blob.core.windows.net`,
  credential
);

/**
 * Generate minimal-permission SAS token for temporary blob upload
 * @param {string} blobName - Name of the blob to grant access to
 * @param {string} clientIp - IP address of the client (for IP restriction)
 * @returns {string} Full blob URL with SAS token
 */
function generateSecureSasToken(blobName, clientIp) {
  const containerClient = blobServiceClient.getContainerClient(containerName);
  const blobClient = containerClient.getBlobClient(blobName);

  // Set SAS token expiration (1 hour from now)
  const startsOn = new Date();
  const expiresOn = new Date(startsOn);
  expiresOn.setHours(startsOn.getHours() + 1); // 1-hour validity

  // Define minimal permissions (write-only, no read/delete)
  const permissions = new BlobSASPermissions();
  permissions.write = true;   // Allow upload
  permissions.create = true;  // Allow creation
  permissions.read = false;   // Deny read (cannot download)
  permissions.delete = false; // Deny delete

  // Generate SAS token with restrictions
  const sasToken = generateBlobSASQueryParameters({
    containerName: containerName,
    blobName: blobName,
    permissions: permissions,
    startsOn: startsOn,
    expiresOn: expiresOn,
    ipRange: { start: clientIp, end: clientIp }, // Bind to client IP
    protocol: 'https', // Enforce HTTPS only
    version: '2021-08-06'
  }, credential).toString();

  const sasUrl = `${blobClient.url}?${sasToken}`;

  console.log('Generated SAS token:');
  console.log(`  Blob: ${blobName}`);
  console.log(`  Permissions: Write/Create only`);
  console.log(`  Expires: ${expiresOn.toISOString()}`);
  console.log(`  IP Restriction: ${clientIp}`);
  console.log(`  Protocol: HTTPS only`);

  return sasUrl;
}

/**
 * Generate read-only SAS token for temporary download (e.g., presigned download link)
 */
function generateReadOnlySasToken(blobName, clientIp, expirationMinutes = 15) {
  const containerClient = blobServiceClient.getContainerClient(containerName);
  const blobClient = containerClient.getBlobClient(blobName);

  const startsOn = new Date();
  const expiresOn = new Date(startsOn);
  expiresOn.setMinutes(startsOn.getMinutes() + expirationMinutes);

  const permissions = new BlobSASPermissions();
  permissions.read = true; // Read-only

  const sasToken = generateBlobSASQueryParameters({
    containerName: containerName,
    blobName: blobName,
    permissions: permissions,
    startsOn: startsOn,
    expiresOn: expiresOn,
    ipRange: { start: clientIp, end: clientIp },
    protocol: 'https',
    version: '2021-08-06'
  }, credential).toString();

  return `${blobClient.url}?${sasToken}`;
}

// Example: Generate upload token for user
const uploadUrl = generateSecureSasToken('uploads/user123/document.pdf', '203.0.113.42');
console.log('\nUpload URL (valid for 1 hour):', uploadUrl);

// Example: Generate short-lived download link
const downloadUrl = generateReadOnlySasToken('reports/monthly-report.pdf', '203.0.113.42', 15);
console.log('\nDownload URL (valid for 15 minutes):', downloadUrl);

// IMPORTANT: Monitor and revoke SAS tokens if compromised
// Azure does not support direct SAS revocation, so use account key rotation
// or stored access policies for revocable SAS tokens

#!/bin/bash
# Enable Microsoft Defender for Storage at subscription level

# Method 1: Azure CLI
az security pricing create \
  --name StorageAccounts \
  --tier Standard \
  --subscription <subscription-id>

echo "✓ Azure Defender for Storage enabled"

# Enable specific threat detection features
az security setting update \
  --name "MCAS" \
  --enabled true \
  --subscription <subscription-id>

echo "✓ Microsoft Cloud App Security integration enabled"

# Configure diagnostic logging (required for threat detection)
az monitor diagnostic-settings create \
  --name "storage-security-logs" \
  --resource "/subscriptions/<sub-id>/resourceGroups/<rg>/providers/Microsoft.Storage/storageAccounts/<account>" \
  --workspace "/subscriptions/<sub-id>/resourceGroups/<rg>/providers/Microsoft.OperationalInsights/workspaces/<workspace>" \
  --logs '[
    {
      "category": "StorageRead",
      "enabled": true,
      "retentionPolicy": { "enabled": true, "days": 90 }
    },
    {
      "category": "StorageWrite",
      "enabled": true,
      "retentionPolicy": { "enabled": true, "days": 90 }
    },
    {
      "category": "StorageDelete",
      "enabled": true,
      "retentionPolicy": { "enabled": true, "days": 90 }
    }
  ]' \
  --metrics '[
    {
      "category": "Transaction",
      "enabled": true,
      "retentionPolicy": { "enabled": true, "days": 90 }
    }
  ]'

echo "✓ Diagnostic logging configured"

# Terraform equivalent (infrastructure/defender.tf)
